import{_ as a,o,c as e,ag as r}from"./chunks/framework.B9unkguw.js";const d=JSON.parse('{"title":"Actuators / Motors (PX4)","description":"","frontmatter":{},"headers":[],"relativePath":"zh/qgc-user-guide/setup_view/px4/actuators.md","filePath":"zh/qgc-user-guide/setup_view/px4/actuators.md"}'),i={name:"zh/qgc-user-guide/setup_view/px4/actuators.md"};function s(n,t,c,u,l,h){return o(),e("div",null,t[0]||(t[0]=[r('<h1 id="actuators-motors-px4" tabindex="-1">Actuators / Motors (PX4) <a class="header-anchor" href="#actuators-motors-px4" aria-label="Permalink to &quot;Actuators / Motors (PX4)&quot;">​</a></h1><p>The Actuators page provides a unified interface for configuring motor and servo outputs on PX4 vehicles (PX4 v1.13+).</p><h2 id="geometry-mixer" tabindex="-1">Geometry / Mixer <a class="header-anchor" href="#geometry-mixer" aria-label="Permalink to &quot;Geometry / Mixer&quot;">​</a></h2><p>The top section displays the vehicle&#39;s actuator geometry, dynamically generated from the mixer configuration. For multirotor vehicles, an SVG diagram shows motor positions — you can click individual motors to select them. Each actuator channel has configurable parameters such as position offsets and tilt angles.</p><h2 id="actuator-outputs" tabindex="-1">Actuator Outputs <a class="header-anchor" href="#actuator-outputs" aria-label="Permalink to &quot;Actuator Outputs&quot;">​</a></h2><p>The right panel shows all output channels with:</p><ul><li><strong>Function</strong> — assign each output to a motor, servo, or other function</li><li><strong>Min / Max</strong> — PWM or DShot output range limits</li><li><strong>Failsafe</strong> — output value when failsafe is triggered</li><li><strong>Disarmed</strong> — output value when the vehicle is disarmed</li></ul><h2 id="actuator-testing" tabindex="-1">Actuator Testing <a class="header-anchor" href="#actuator-testing" aria-label="Permalink to &quot;Actuator Testing&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Remove all propellers before testing actuators.</p></div><p>With the safety switch toggled, individual actuator sliders appear for testing each channel. An optional <strong>All Motors</strong> slider allows spinning all motors simultaneously at low throttle for verification.</p><h2 id="actuator-actions" tabindex="-1">Actuator Actions <a class="header-anchor" href="#actuator-actions" aria-label="Permalink to &quot;Actuator Actions&quot;">​</a></h2><p>Dynamic action buttons (e.g., beep, identify, 3D mode) are shown based on the vehicle&#39;s actuator configuration. The <strong>motor identification</strong> feature spins motors one at a time to verify correct wiring and rotation direction.</p>',12)]))}const g=a(i,[["render",s]]);export{d as __pageData,g as default};
